package main

import (
	"embed"
	"fmt"
	"runtime/debug"
	"strings"
)

// go:generate sh -c "printf 'Generated by go generate\\n' > generated.txt"

// Embedding content into your program:
//
//go:embed assets/message.txt
var embeddedMessage string

// Embedding hidden files:
//
//go:embed .hidden/secret.txt
var hiddenFiles embed.FS

func main() {
	// Using go run to try out small programs:
	// this package is intentionally small and runnable on its own.
	fmt.Println("embedded message:", strings.TrimSpace(embeddedMessage))

	secret, err := hiddenFiles.ReadFile(".hidden/secret.txt")
	if err != nil {
		fmt.Println("read hidden embedded file error:", err)
		return
	}
	fmt.Println("embedded hidden file:", strings.TrimSpace(string(secret)))

	// Reading the build info inside a Go binary:
	// debug.ReadBuildInfo reports module and dependency build metadata
	// when the binary contains it.
	if info, ok := debug.ReadBuildInfo(); ok {
		fmt.Println("main module path:", info.Main.Path)
		fmt.Println("main module version:", info.Main.Version)
	} else {
		fmt.Println("build info unavailable")
	}

	// Build tags are selected at compile time and usually demonstrated
	// with separate tagged files. This lesson keeps the explanation in notes
	// because the main package stays portable and simple.
	fmt.Println("see notes.md for build tags, cross-compilation, go generate, and tool usage")
}
